#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int count_inversions(int *arr, int n) {
    int inversions = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (arr[i] > arr[j]) {
                inversions++;
            }
        }
    }
    return inversions;
}

int calculate_permutations(int *P, int l1, int r1, int l2, int r2) {
    int S = r1 - l1 + 1;
    int *Q = (int*)malloc(S * sizeof(int));
    for (int i = 0; i < S; i++) {
        Q[i] = i + 1;
    }
    int count = 0;
    do {
        int valid = 1;
        for (int i = 0; i < S; i++) {
            if (Q[i] + l1 - 1 >= P[i + l2 - 1]) {
                valid = 0;
                break;
            }
        }
        if (valid) {
            count++;
        }
    } while (next_permutation(Q, Q + S));
    free(Q);
    return count % MOD;
}

int next_permutation(int *arr, int *end) {
    int *i = end - 2;
    while (i >= arr && *i >= *(i + 1)) {
        --i;
    }
    if (i < arr) {
        return 0;
    }
    int *j = end - 1;
    while (*j <= *i) {
        --j;
    }
    int temp = *i;
    *i = *j;
    *j = temp;
    int *left = i + 1;
    int *right = end - 1;
    while (left < right) {
        temp = *left;
        *left = *right;
        *right = temp;
        ++left;
        --right;
    }
    return 1;
}

