import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int[] P = new int[N];
            for (int i = 0; i < N; i++) {
                P[i] = sc.nextInt();
            }
            for (int i = 0; i < M; i++) {
                int l1 = sc.nextInt() - 1;
                int r1 = sc.nextInt() - 1;
                int l2 = sc.nextInt() - 1;
                int r2 = sc.nextInt() - 1;
                System.out.println(calculatePermutations(P, l1, r1, l2, r2));
            }
        }
    }
    public static int calculatePermutations(int[] P, int l1, int r1, int l2, int r2) {
        int S = r1 - l1 + 1;
        int[] Q = new int[S];
        for (int i = 0; i < S; i++) {
            Q[i] = i + 1;
        }
        int count = 0;
        do {
            int valid = 1;
            for (int i = 0; i < S; i++) {
                if (Q[i] + l1 >= P[i + l2]) {
                    valid = 0;
                    break;
                }
            }
            if (valid) {
                count++;
            }
        } while (nextPermutation(Q));
        return count % MOD;
    }
    public static boolean nextPermutation(int[] arr) {
        int i = arr.length - 2;
        while (i >= 0 && arr[i] >= arr[i + 1]) {
            i--;
        }
        if (i < 0) {
            return false;
        }
        int j = arr.length - 1;
        while (j > i && arr[j] <= arr[i]) {
            j--;
        }
        int temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
        int left = i + 1;
        int right = arr.length - 1;
        while (left < right) {
            temp = arr[left];
            arr[left] = arr[right];
            arr[right] = temp;
            left++;
            right--;
        }
        return true;
    }
}

