import sys
import itertools
MOD = 1000000007

def calculate_permutations(P, l1, r1, l2, r2):
    S = r1 - l1 + 1
    Q = list(range(1, S + 1))
    count = 0
    for p in itertools.permutations(Q):
        valid = True
        for i in range(S):
            if p[i] + l1 >= P[i + l2]:
                valid = False
                break
        if valid:
            count += 1
    return count % MOD

def main():
    T = int(sys.stdin.readline().strip())
    for _ in range(T):
        N, M = map(int, sys.stdin.readline().strip().split())
        P = list(map(int, sys.stdin.readline().strip().split()))
        for _ in range(M):
            l1, r1, l2, r2 = map(int, sys.stdin.readline().strip().split())
            print(calculate_permutations(P, l1 - 1, r1 - 1, l2 - 1, r2 - 1))
if __name__ == '__main__':
    main()

