const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const MOD = 1000000007;

function calculatePermutations(P, l1, r1, l2, r2) {
    const S = r1 - l1 + 1;
    const Q = Array.from({ length: S }, (_, i) => i + 1);
    let count = 0;
    const permutations = getPermutations(Q);
    for (const p of permutations) {
        let valid = true;
        for (let i = 0; i < S; i++) {
            if (p[i] + l1 >= P[i + l2]) {
                valid = false;
                break;
            }
        }
        if (valid) {
            count++;
        }
    }
    return count % MOD;
}

function getPermutations(arr) {
    if (arr.length === 1) return [arr];
    const result = [];
    for (let i = 0; i < arr.length; i++) {
        const rest = arr.slice(0, i).concat(arr.slice(i + 1));
        for (const p of getPermutations(rest)) {
            result.push([arr[i]].concat(p));
        }
    }
    return result;
}

